/* Route declarations for the app */
import {React, lazy, Suspense} from 'react'
// import Loader from '../assets/images/loader.gif'
import CircularProgress from '@mui/material/CircularProgress';
const  Home = lazy(()=>import('../pages/Home'))
const  AboutUs = lazy(()=>import('../pages/AboutUs'))
const  ContactUs = lazy(()=>import('../pages/ContactUs'))
const  Projects = lazy(()=>import('../pages/Projects'))
const  NoPageFound = lazy(()=>import('../pages/NoPageFound'))

const useLoader = <div className='loader-parent'><CircularProgress className='loader'/></div>

const routData = [
    {
        id: 'route-001',
        path: '/home',
        component: <Suspense fallback={useLoader}><Home/></Suspense>,
        requiresAuth: false,
    },
    {
        id: 'route-002',
        path: '/contact-us',
        component: <Suspense fallback={useLoader}><ContactUs/></Suspense>,
        requiresAuth: false,
    },
    {
        id: 'route-003',
        path: '/about-us',
        component: <Suspense fallback={useLoader}><AboutUs/></Suspense>,
        requiresAuth: false,
    },

    {
        id: 'route-003',
        path: '/projects',
        component: <Suspense fallback={useLoader}><Projects/></Suspense>,
        requiresAuth: false,
    },

    {
        id: 'route-000',
        path: '*',
        component: <Suspense fallback={useLoader}><NoPageFound/></Suspense>,
        requiresAuth: false,
    },
];

export default routData;
