import React, { useEffect, Fragment} from 'react';
import { Routes, Route, useNavigate, useLocation } from 'react-router-dom';
import { AppBarComponent } from '../components';
import Footer from '../components/Footer/Footer';
// import { useDispatch } from 'react-redux';
// import {incrementByAmount} from '../../components/store/progressTop'
const AppContent = ({ routes, setProgress}) => {
    // const dispatch = useDispatch();

    const navigate = useNavigate();
    const location = useLocation();
    useEffect(() => {
        location.pathname === '/' && navigate('/home');
        location.pathname === '/muhammad-abu-sufyan' && navigate('/home');
        location.pathname === '' && navigate('/home');

        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    

    return (
        <Fragment>
            {location.pathname !== '/' ? <AppBarComponent />  : null}
            <Routes>
                {routes.map((route) => (
                    <Route key={route.id} path={route.path} element={ route.component} />
                ))}
            </Routes>
            {location.pathname !== '/login' && <Footer />}
        </Fragment>
    );
};

export default AppContent;
